const express = require('express');
const multer = require('multer');
const libxmljs = require('libxmljs');

const app = express();
const upload = multer({ storage: multer.memoryStorage() });

app.post('/api/upload-xml-config', upload.single('xmlFile'), (req, res) => {
  try {
    if (!req.file) {
      return res.status(400).json({ error: 'No file uploaded' });
    }

    const xmlContent = req.file.buffer.toString('utf-8');

    const xmlDoc = libxmljs.parseXml(xmlContent, {
      noent: false,
      nonet: true,
      dtdload: false,
      dtdvalid: false,
      doctype: false
    });

    const configObject = parseXmlToObject(xmlDoc.root());

    res.json({
      success: true,
      configuration: configObject
    });

  } catch (error) {
    res.status(400).json({
      success: false,
      error: 'Failed to parse XML',
      message: error.message
    });
  }
});

function parseXmlToObject(node) {
  const obj = {};

  if (node.attrs().length > 0) {
    obj['@attributes'] = {};
    node.attrs().forEach(attr => {
      obj['@attributes'][attr.name()] = attr.value();
    });
  }

  const children = node.childNodes();
  const textContent = node.text().trim();

  if (children.length === 0 || (children.length === 1 && children[0].type() === 'text')) {
    if (textContent) {
      if (obj['@attributes']) {
        obj['@value'] = textContent;
      } else {
        return textContent;
      }
    }
    return obj;
  }

  children.forEach(child => {
    if (child.type() === 'element') {
      const childName = child.name();
      const childValue = parseXmlToObject(child);

      if (obj[childName]) {
        if (Array.isArray(obj[childName])) {
          obj[childName].push(childValue);
        } else {
          obj[childName] = [obj[childName], childValue];
        }
      } else {
        obj[childName] = childValue;
      }
    }
  });

  return obj;
}

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});